A different solution:

grr2 <- function( rn ) {
  f <- function( i ) {
    if ( 0 == i %% 2 ) seq.int( i )
    else seq( i, 1 )
  }
  L <- lapply( seq.int( rn - 1 ), f )
  do.call( c, L )
}

On April
